        _ = try? performTransaction(amount: 100, type: .debit, description: "Groceries", fromAccountID: checkingAccount.id, toAccountID: nil)
        _ = try? performTransaction(amount: 200, type: .credit, description: "Salary Deposit", fromAccountID: nil, toAccountID: savingsAccount.id)
