    @discardableResult
    func performTransaction(amount: Decimal, type: TransactionType, description: String, fromAccountID: UUID?, toAccountID: UUID?) throws -> Transaction {
        guard amount > 0 else {
            throw TransactionManagerError.negativeAmount
        }

        var sourceAccount: Account?
        var destinationAccount: Account?

        if let fromID = fromAccountID {
            guard let account = accounts[fromID] else { throw TransactionManagerError.accountNotFound }
            sourceAccount = account
        }

        if let toID = toAccountID {
            guard let account = accounts[toID] else { throw TransactionManagerError.accountNotFound }
            destinationAccount = account
        }
        
        // Ensure that for a debit, a source account is provided
        // And for a credit, a destination account is provided
        // And prevent scenarios like debit without source or credit without destination
        if type == .debit {
            guard let account = sourceAccount else { throw TransactionManagerError.accountNotFound } // Debit must have source
            guard account.balance >= amount else { throw TransactionManagerError.insufficientFunds }
            accounts[account.id]?.balance -= amount
            let transaction = Transaction(accountID: account.id, type: .debit, amount: amount, description: description)
