            let transaction = Transaction(accountID: account.id, type: .credit, amount: amount, description: description)
            transactions[account.id, default: []].append(transaction)
            saveData()
            return transaction
        }
    }

    func performTransfer(amount: Decimal, description: String, fromAccountID: UUID, toAccountID: UUID) throws {
        guard amount > 0 else {
            throw TransactionManagerError.negativeAmount
        }
        guard fromAccountID != toAccountID else {
            throw TransactionManagerError.selfTransferNotAllowed
        }

        guard let sourceAccount = accounts[fromAccountID] else { throw TransactionManagerError.accountNotFound }
        guard let destinationAccount = accounts[toAccountID] else { throw TransactionManagerError.accountNotFound }
        guard sourceAccount.balance >= amount else { throw TransactionManagerError.insufficientFunds }

        // Perform debit from source
        accounts[fromAccountID]?.balance -= amount
        let debitTransaction = Transaction(accountID: fromAccountID, type: .debit, amount: amount, description: "Transfer to \(destinationAccount.name): \(description)")
        transactions[fromAccountID, default: []].append(debitTransaction)

        // Perform credit to destination
        accounts[toAccountID]?.balance += amount
        let creditTransaction = Transaction(accountID: toAccountID, type: .credit, amount: amount, description: "Transfer from \(sourceAccount.name): \(description)")
        transactions[toAccountID, default: []].append(creditTransaction)

        saveData()
    }
